// 分批获取所有一级标题段落索引并应用格式
var doc = Application.ActiveDocument;
var paras = doc.Paragraphs;
var targetIndices = [];
var batchSize = 50;
for (var i = 0; i < paras.Count; i++) {
    var txt = paras.Item(i).Range.Text.replace(/\r$/, '');
    if (/^[1-9][0-9]*\s+/.test(txt)) {
        targetIndices.push(i);
    }
}
var results = { total: targetIndices.length, applied: 0 };
for (var b = 0; b < targetIndices.length; b += batchSize) {
    var batch = targetIndices.slice(b, b + batchSize);
    for (var j = 0; j < batch.length; j++) {
        var p = paras.Item(batch[j]);
        var range = p.Range;
        range.Font.NameCN = "黑体";
        range.Font.Size = 16;
        range.Font.Bold = true;
        range.ParagraphFormat.Alignment = 1;
        range.ParagraphFormat.SpaceBefore = 12;
        range.ParagraphFormat.SpaceAfter = 6;
        range.ParagraphFormat.FirstLineIndent = 0;
        results.applied++;
    }
}
return results;

